// dist/libs/ontouml2alloy/ontouml2alloy-cli.js
var fs = require("fs");
var path = require("path");
var {
  parseArgs
} = require("util");
var ontoumlLib = require_ontouml();
var {
  serializationUtils
} = ontoumlLib;
var {
  Ontouml2Alloy
} = require_ontouml2alloy();
var {
  values,
  positionals
} = parseArgs({
  args: process.argv.slice(2),
  allowPositionals: true,
  options: {
    "allow-abstract-leaf-instances": {
      type: "boolean",
      default: false
    }
  }
});
var inputFile = positionals[0];
var outputDir = positionals[1] ?? path.join(__dirname, "alloy");
var allowAbstractLeafInstances = values["allow-abstract-leaf-instances"];
fs.mkdirSync(outputDir, {
  recursive: true
});
var jsonContent = fs.readFileSync(inputFile, "utf-8");
var model;
try {
  model = serializationUtils.parse(jsonContent);
} catch (_err) {
  console.error(JSON.stringify({
    errors: ["Invalid input model: could not parse/deserialize OntoUML JSON."]
  }));
  process.exit(1);
}
var transformer = new Ontouml2Alloy(model, {
  allowAbstractLeafInstances
});
var {
  result,
  issues
} = transformer.run();
if (!result) {
  console.error(JSON.stringify({
    errors: (issues || []).map((e) => e.description)
  }));
  process.exit(1);
}
fs.writeFileSync(path.join(outputDir, "main.als"), result.mainModule, "utf-8");
fs.writeFileSync(path.join(outputDir, "world_structure.als"), result.worldStructureModule, "utf-8");
fs.writeFileSync(path.join(outputDir, "ontological_properties.als"), result.ontologicalPropertiesModule, "utf-8");
fs.writeFileSync(path.join(outputDir, "transformation_metadata.json"), JSON.stringify(result.transformationMetadata, null, 2), "utf-8");
process.stdout.write(JSON.stringify({
  issues: issues || []
}));
